var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"카운터 아카데미 초등부 교실- <color=#ffd34c>초적성 초계발 </color>수업\\n  제안 및 담당 교사, 브라우니 무어","JPN":"カウンターアカデミー初等部教室 - <color=#ffd34c>超敵性超啓発</color>授業\\n提案および担当教師、ブラウニー・ムーア","ENG":"[[","TWN":"制裁者學院小學部教室－<color=#ffd34c>初適性超啟發</color>課程\\n提案及負責教師：布朗尼‧摩爾","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"카운터의 능력이 어떤 식으로 개화되는 것인지는 아직도 정확히 규명된 바가 없다.","JPN":"カウンターの能力がどういう仕組みで開花するものなのかについては、まだ正確に究明されていない。","ENG":"It is not yet clear exactly how Counters develop their abilities.","TWN":"制裁者的能力究竟是以什麼形式覺醒的，至今仍未完全釐清。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 선생님은 카운터에게 있어 가장 중요한 것은 단연 의지라고 생각해!","JPN":"でも先生は、カウンターにとっていちばん大事なことは断然「意志」だと思う！","ENG":"But I think determination is the most important!","TWN":"但老師認為，對制裁者來說，最重要的絕對是意志！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"누군가 타의적으로 심어주는 동기가 아닌 마음 속에 살아 움직이는 자신만의 동기!","JPN":"誰かに植えつけられた動機じゃなく、自分の心に生きている自分だけの動機！","ENG":"It has to do with you providing the motivation, not someone else!","TWN":"不是被他人強加的動機，而是存在於內心、只屬於自己的動機！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그것을 찾게 되었을 때, 비로소 카운터는 자신만의 힘을 찾게 되는 것이지!","JPN":"それに気づいた瞬間、カウンターは初めて自分だけの力に目覚めるの！","ENG":"Once you find that, it will be when you discover your Counter powers!","TWN":"當你找到那個動機時，制裁者才能找到屬於自己的力量！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그런 의미에서, 오늘은 각자 자신의 멋진 꿈을 말하는 시간을 가져보기로 할까-?","JPN":"というわけで、今日はみんなで自分の夢について話してみようか？","ENG":"On that note, how about we share with each other what our dreams are today?","TWN":"基於這一點，今天就讓大家分享各自的夢想吧～？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"…그래서, 제 꿈은 많은 사람들을 지켜주는 히어로가 되는 것입니다!","JPN":"……だから、私の夢はたくさんの人を守るヒーローになることです！","ENG":"...So, my dream is to become a hero who protects many people!","TWN":"……所以說，我的夢想是成為守護很多人的英雄！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아, 친구도 많이 사귀고 싶어요! 이상입니다!","JPN":"あ、友だちもたくさん作りたい！　以上です！","ENG":"Oh, and I want to make a lot of friends! That's all!","TWN":"啊，還想交很多朋友！就是這樣！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 온 세상을 지배하여, 모든 인간을 내 하수인으로 부릴 것이니라.","JPN":"吾輩は全世界を支配し、すべての人間を下僕にする。","ENG":"I want to rule the world and make all humans do my bidding.","TWN":"我要統治全世界，讓所有人類都成為我的手下！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그런 다음 하수인들에게 매일매일 사탕과 과자를 공물로 바치게 할 것이다.","JPN":"そして下僕たちに毎日キャンディとお菓子を供えさせるのだ。","ENG":"I will make my servants offer candy and sweets to me every day.","TWN":"然後命令手下們每天獻上糖果和點心！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"우리 꿈은 모두가 사이좋게 지내는 거야!","JPN":"あたしたちの夢はみんなと仲よくすること！","ENG":"Our dream is for everyone to get along!","TWN":"我們的夢想是大家都能和睦相處！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"\xA0맛있는 것도 같이 먹고-!","JPN":"おいしいものもみんなといっしょに食べるんだ！","ENG":"\xA0And eat delicious food together!","TWN":"\xA0一起吃好吃的～！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"뭔가 대단한 수업인 것처럼 말하더니… 겨우 자기소개하기? 뭔가 속은 기분이야.","JPN":"なんかたいそうな授業をするみたいに言ってたけど……ただの自己紹介じゃん。騙された気分。","ENG":"The class sounded so important... but it's just about introducing yourself. I feel tricked.","TWN":"說得好像是什麼了不起的課程……結果只是自我介紹而已？感覺被騙了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그래도 다들 꿈이 있으니까, 그걸 서로에게 말하는 것만으로도 의미가 있는 것 같아.","JPN":"でもみんな夢があるんだから、それを話し合うことに意味があるんじゃないかな。","ENG":"But because everyone has their dreams, I think it's worth sharing it with each other.","TWN":"不過大家都有夢想，能像這樣對彼此說出口，本身就很有意義了吧。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"초등학생 꿈이 다 거기서 거기지 뭐. 아주 비현실적이거나, 당장의 욕구에 충실하거나.","JPN":"所詮は小学生の夢でしょう。きわめて非現実的か、目の前の欲望に忠実なものとか。","ENG":"Dreams kids our age have are pretty much the same. They are all unrealistic, or are about immediate desires.","TWN":"小學生的夢想都差不多啦。不是超級不現實，就是完全忠於眼前的慾望。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"결국 진짜 원하는 꿈의 윤곽이 잡히기 시작하는 건 사춘기가 지나서부터거든.","JPN":"本当に望む夢がある程度決まってくるのは、思春期が過ぎてからなんだよね。","ENG":"It's only after puberty when you really start thinking of what your dreams are.","TWN":"真正想要的夢想，要過了青春期才會開始成形。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아르티의 지금 꿈은 뭔데?","JPN":"じゃあ、アルティの今の夢は何？","ENG":"Then Arti, what's your dream right now?","TWN":"那阿爾蒂現在的夢想是什麼？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"최강의 히어로 뒤에서 그를 돕는 조수.","JPN":"最強のヒーローをサポートする助手。","ENG":"To become the assistant who aids the strongest hero.","TWN":"在最強英雄身後輔佐他的助手。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"그 꿈도 아르티가 사춘기 지나서 어른이 되면 바뀌는 거야?","JPN":"その夢も、アルティが思春期を経て大人になったら変わるの？","ENG":"Do you think that dream will change after puberty and you become an adult?","TWN":"那個夢想等阿爾蒂過了青春期、變成大人後也會改變嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"난 사춘기 따위 겪지 않아. 이미 정신적으로 성숙한 어른이니까.","JPN":"ぼくに思春期なんて訪れないよ。ぼくはすでに精神的に成熟した大人だから。","ENG":"I won't have to go through puberty. I'm already an emotionally mature adult.","TWN":"我才不會經歷什麼青春期呢。我在精神上早就是成熟的大人了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"뭐야. 혼자만 건너뛰는 게 어딨어. 아르티 언니 치사해.","JPN":"なにそれ～1人だけ飛び越すなんてずるいよ、アルティお姉ちゃん。","ENG":"Huh? Why do you get to skip it? That's so unfair, Arti.","TWN":"什麼啊，哪有人自己跳過的。阿爾蒂姐姐好小氣。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"맞아- 치사해-","JPN":"そうだよ、ずるいずるい。","ENG":"Yeah. So unfair.","TWN":"對啊～好小氣～"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"근데 뭘 건너뛰어? 나도 뛰는 거 잘해-!","JPN":"って、何を飛び越したの？　飛ぶのはぼくも自信あるよ！","ENG":"But what is she skipping? I'm good at skipping down the street too!","TWN":"不過你跳過什麼？我也很會跳耶～！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_HATE"},"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"자, 그럼 다음은 차례는… 케이시네.","JPN":"さあて、次は……ケイシーね。","ENG":"Now, who's next? Kaci?","TWN":"好，那下一位是……卡西。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어… 저는… 그러니까…","JPN":"えっと……あたしは……その……","ENG":"Uh... I... um...","TWN":"呃……我……那個……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"잘 모르겠어요. 스카이나 모르가나 양처럼 멋진 꿈은 아직 없거든요.","JPN":"よく……わかりません。スカイやモルガナさんみたいな素敵な夢は、まだないんです。","ENG":"I'm not sure. I haven't thought about my dream like Sky or Morgana.","TWN":"我不太清楚。我還沒有像絲凱或莫莫那樣帥氣的夢想。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그래? 그거 의외인걸?","JPN":"そうなの？　それは意外ね。","ENG":"Oh? But I don't think that's true.","TWN":"是嗎？這讓我很意外呢。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"케이시는 이번 체력실기에서 성적이 엄청 좋았잖아? 그 장점을 살려보는 건 어때?","JPN":"ケイシーはこの前の体力実技で、すばらしい成績を収めたよね？　その長所を活かしてみるのはどう？","ENG":"Didn't you do very well on the physical fitness evaluation, Kaci? Then how about using that as your strong point?","TWN":"卡西這次體能評測成績不是非常好嗎？要不要試著發揮這個優點看看？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"역시… 그러는 편이 좋을까요?","JPN":"やっぱり……そのほうがいいんでしょうか？","ENG":"I guess... that could work?","TWN":"果然……這樣比較好嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};